def range_summary(nums):
    if not nums:  # Handle empty list edge case
        return ''

    unique_nums = sorted(set(nums))
    ranges = []
    start = None

    for num in unique_nums:
        if start is None or num != start + 1:
            if start is not None:
                ranges.append(f'{start}-{unique_nums[unique_nums.index(start) - 1]}' if unique_nums.index(start) > 0 else f'{start}')
            start = num
        elif start == num:
            continue

    if start is not None:
        ranges.append(f'{start}-{unique_nums[unique_nums.index(start) - 1]}' if unique_nums.index(start) > 0 else f'{start}')

    return ','.join(ranges)
